#include <stdio.h>

int main() {
    int T, a, b;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d %d", &a, &b) != 2) break;
        if (b == 0) {
            printf("-1\n");
        } else {
            printf("%.1f\n", (double)a / b);
        }
    }
    return 0;
}

