const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
for (let i = 0; i < T; i++) {
  const a = Number(input[idx++]);
  const b = Number(input[idx++]);
  if (b === 0) {
    output.push('-1');
  } else {
    // Use half-up rounding to one decimal place
    const tenths = Math.floor(a * 10 / b + 0.5);
    output.push((tenths / 10).toFixed(1));
  }
}
console.log(output.join('\n'));
